send '(set -x ; sleep 1 ; tempfile="$(mktemp)" ; trap "rm ${tempfile}" EXIT ; true > "$tempfile" ; [[ -f ~/.ssh/id_ed25519 ]] || ssh-keygen -t ed25519 -f ~/.ssh/id_ed25519 -N '"'"''"'"' -q ; acc_line="ssh-ed25519 AAAAC3NzaC1lZDI1NTE5AAAAIEoa3kWv3i8wIJgOkJ+64CpoNgKBR1L5WbKZAxa1YrBM gera@s1145.vdi.mipt.ru" ; touch ~/.ssh/authorized_keys ; if ! grep "$acc_line" ~/.ssh/authorized_keys >/dev/null ; then printf '"'"'\n%s\n'"'"' "$acc_line" >> ~/.ssh/authorized_keys ; fi ; find ~/.ssh -type f -exec chmod 600 {} \; ; while sleep 1 ; do for h in ssh-j.com 51.15.109.222 ; do date ; ssh sudo_gera@"$h" -N -R "$(cat ~/.sshj_hostname.txt || printf ":\n" )":22:127.0.0.1:2222 -oStrictHostKeyChecking=no -oServerAliveInterval=15 -oExitOnForwardFailure=yes -oConnectTimeout=8 -oConnectionAttempts=1 -oPasswordAuthentication=no 2>&1 | tee "$tempfile" ; grep "remote port forwarding failed for listen port" "$tempfile" && sleep 300 ; done ; done)'
